        let charts = {};
        let bsrRollupMode = false;
        function setBSRRollup(mode) {
            bsrRollupMode = mode;
            const daily = document.getElementById('bsrRollupDaily');
            const weekly = document.getElementById('bsrRollupWeekly');
            if (daily) {
                daily.style.background = mode ? '#fff' : '#667eea';
                daily.style.color = mode ? '#555' : '#fff';
                daily.style.fontWeight = mode ? '500' : '600';
            }
            if (weekly) {
                weekly.style.background = mode ? '#667eea' : '#fff';
                weekly.style.color = mode ? '#fff' : '#555';
                weekly.style.fontWeight = mode ? '600' : '500';
            }
            renderBSRTab();
        }
        function getWeekStart(dateStr) {
            const d = new Date(dateStr + 'T00:00:00');
            const day = d.getDay(); // 0=Sun,1=Mon..6=Sat
            const diff = day === 0 ? -6 : 1 - day; // shift to Monday
            d.setDate(d.getDate() + diff);
            return d.toISOString().slice(0, 10);
        }
        function weekLabel(weekStartStr) {
            const d = new Date(weekStartStr + 'T00:00:00');
            return 'Wk ' + (d.getMonth()+1) + '/' + d.getDate();
        }
        function buildWeeklyData(dates, ranks) {
            // Returns { weekStarts: [...sorted], avgRanks: [...] }
            const weeks = {};
            dates.forEach((date, i) => {
                const ws = getWeekStart(date);
                if (!weeks[ws]) weeks[ws] = [];
                if (ranks[i] !== null) weeks[ws].push(ranks[i]);
            });
            const weekStarts = Object.keys(weeks).sort();
            const avgRanks = weekStarts.map(ws => {
                const vals = weeks[ws];
                if (vals.length === 0) return null;
                return Math.round(vals.reduce((a,b) => a+b, 0) / vals.length * 10) / 10;
            });
            return { weekStarts, avgRanks };
        }
